public class Main {
    public static void main(String[] args) {

        String rawEmail = "  Rahul.Sharma@Example.COM  ";

        // Clean up
        String trimmed = rawEmail.trim();           // remove spaces
        String lower   = trimmed.toLowerCase();     // normalise case
        System.out.println("Cleaned: " + lower);

        // Extract username (before @)
        int    atIndex  = lower.indexOf("@");
        String username = lower.substring(0, atIndex);
        System.out.println("Username: " + username);

        // Basic validation
        boolean hasAt  = lower.contains("@");
        boolean hasDot = lower.contains(".");
        System.out.println("Valid email: " + (hasAt && hasDot));

        // Length and case check
        System.out.println("Length: " + lower.length());
        System.out.println("Uppercase: " + lower.toUpperCase());

        // Replace domain
        String updated = lower.replace("example.com", "codeguru.ai");
        System.out.println("Updated: " + updated);
    }
}

